using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ServerShipmentService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await db.Shipments
            .OrderByDescending(s => s.ShippedDate)
            .Select(s => ToDto(s))
            .ToListAsync();
    }

    public async Task<ShipmentDto?> GetByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = await db.Shipments
            .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return shipment is null ? null : ToDto(shipment);
    }

    public async Task<ShipmentDto?> UpdateStatusAsync(int id, ShipmentStatus newStatus)
    {
        var shipment = await db.Shipments.FindAsync(id);
        if (shipment is null) return null;

        shipment.Status = newStatus;
        if (newStatus == ShipmentStatus.Delivered)
            shipment.ActualDelivery = DateTime.UtcNow;

        await db.SaveChangesAsync();
        return ToDto(shipment);
    }

    private static ShipmentDto ToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = s.Status,
        ShippedDate = s.ShippedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        ActualDelivery = s.ActualDelivery,
        RecipientName = s.RecipientName,
        CustomerEmail = s.CustomerEmail
    };
}

using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments");

        group.MapGet("/", async (IShipmentService service) =>
        {
            return Results.Ok(await service.GetAllShipmentsAsync());
        }).RequireAuthorization(policy => policy.RequireRole("Dispatcher"));

        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
        {
            var shipment = await service.GetByTrackingNumberAsync(trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        }).RequireAuthorization();

        group.MapPut("/{id:int}/status", async (int id, ShipmentStatus newStatus, IShipmentService service) =>
        {
            var updated = await service.UpdateStatusAsync(id, newStatus);
            return updated is null ? Results.NotFound() : Results.Ok(updated);
        }).RequireAuthorization(policy => policy.RequireRole("Dispatcher"));
    }
}

